def is_prime(num):
    """Check if a number is prime."""
    if num <= 1:
        return False
    if num == 2:
        return True  # 2 is the only even prime number
    if num % 2 == 0:
        return False  # Exclude even numbers greater than 2
    for i in range(3, int(num**0.5) + 1, 2):
        if num % i == 0:
            return False
    return True

def fibonacci_generator():
    """Generate Fibonacci numbers starting from 1."""
    a, b = 1, 1
    while True:
        yield a
        a, b = b, a + b

def prime_fib(n: int):
    """Return the n-th Fibonacci number that is also prime."""
    fib_gen = fibonacci_generator()
    count = 0
    while count < n:
        fib_num = next(fib_gen)
        if is_prime(fib_num):
            count += 1
            if count == n:
                return fib_num
